// PGlite path: wrap each migration file in a transaction for atomicity
// 1. Create tracking table if not exists (outside migration transaction)
await client.exec(
  `CREATE TABLE IF NOT EXISTS "__drizzle_migrations" ("hash" text PRIMARY KEY, "created_at" bigint)`
)
const applied = new Set<string>()
try {
  const result = client.query?.('SELECT hash FROM "__drizzle_migrations"')
  for (const row of (result?.rows ?? []) as {hash: string}[]) applied.add(row.hash)
} catch { /* table may not exist yet on very first run */ }

const migrations = readMigrationFiles({ migrationsFolder: folder })
for (const migration of migrations) {
  if (applied.has(migration.hash)) continue
  // Wrap entire migration file in a transaction so DDL is atomic
  await client.exec('BEGIN')
  try {
    for (const sql of migration.sql) {
      await client.exec(sql)
    }
    // Record applied migration (hash is SHA-256 hex — safe from SQL injection)
    await client.exec(
      `INSERT INTO "__drizzle_migrations" ("hash", "created_at") VALUES ('${migration.hash}', ${Date.now()})"
    )
    await client.exec('COMMIT')
  } catch (error) {
    await client.exec('ROLLBACK')
    throw error
  }
}

