// makeLocalPgAdapter — auto-apply migrations on first connect
export function makeLocalPgAdapter(options?: { skipMigrations?: boolean }): Interface {
  // ... adapter construction ...

  // Access the underlying PGlite client to apply migrations
  const raw = (Database.Client() as any).$client
  const pgClient = {
    $client: raw,
  } as any

  if (!options?.skipMigrations) {
    applyMigrations(pgClient).catch((err) => {
      console.warn("[db] Failed to auto-apply migrations to local PGlite (non-fatal):", err)
    })
  }

  return Service.of({ query, transaction, afterCommit })
}

